namespace sv_36f4efedc28845b281d0f0740479c67c.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@* Leaf component: renders a single work entry with editable fields *@

<div style="border:1px solid #dee2e6; border-radius:8px; padding:1rem; margin-bottom:1rem; background:#f8f9fa;">
    <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.75rem;">
        <strong>Position @(Index + 1)</strong>
        @if (ShowRemove)
        {
            <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
        }
    </div>

    <div style="display:grid; grid-template-columns:1fr 1fr; gap:0.75rem;">
        <div>
            <label class="form-label">Company Name <span style="color:red;">*</span></label>
            <input class="form-control" value="@Entry.Company"
                   @onchange="e => Update(Entry with { Company = (string?)e.Value ?? string.Empty })" />
        </div>
        <div>
            <label class="form-label">Job Title <span style="color:red;">*</span></label>
            <input class="form-control" value="@Entry.Title"
                   @onchange="e => Update(Entry with { Title = (string?)e.Value ?? string.Empty })" />
        </div>
        <div>
            <label class="form-label">Start Date <span style="color:red;">*</span></label>
            <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                   @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? string.Empty) })" />
        </div>
        <div>
            <label class="form-label">End Date</label>
            <input type="date" class="form-control" value="@(Entry.EndDate?.ToString("yyyy-MM-dd"))"
                   disabled="@IsCurrent"
                   @onchange="e => Update(Entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })" />
            <div class="form-check mt-1">
                <input type="checkbox" class="form-check-input" id="@($"current-{Index}")"
                       checked="@IsCurrent" @onchange="ToggleCurrent" />
                <label class="form-check-label" for="@($"current-{Index}")">Currently working here</label>
            </div>
        </div>
    </div>

    <div style="margin-top:0.75rem;">
        <label class="form-label">Description</label>
        <textarea class="form-control" rows="3" value="@Entry.Description"
                  @onchange="e => Update(Entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null;

    private async Task Update(WorkEntry updated) => await OnChanged.InvokeAsync(updated);

    private async Task ToggleCurrent(ChangeEventArgs e)
    {
        var current = (bool?)e.Value ?? false;
        var updated = current
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        await OnChanged.InvokeAsync(updated);
    }
}

@* Leaf component: renders a single reference with editable fields *@

<div style="border:1px solid #dee2e6; border-radius:8px; padding:1rem; margin-bottom:1rem; background:#f8f9fa;">
    <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.75rem;">
        <strong>Reference @(Index + 1)</strong>
        @if (ShowRemove)
        {
            <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
        }
    </div>

    <div style="display:grid; grid-template-columns:1fr 1fr; gap:0.75rem;">
        <div>
            <label class="form-label">Name <span style="color:red;">*</span></label>
            <input class="form-control" value="@Reference.Name"
                   @onchange="e => Update(Reference with { Name = (string?)e.Value ?? string.Empty })" />
        </div>
        <div>
            <label class="form-label">Relationship <span style="color:red;">*</span></label>
            <input class="form-control" value="@Reference.Relationship"
                   @onchange="e => Update(Reference with { Relationship = (string?)e.Value ?? string.Empty })" />
        </div>
        <div>
            <label class="form-label">Email <span style="color:red;">*</span></label>
            <input type="email" class="form-control" value="@Reference.Email"
                   @onchange="e => Update(Reference with { Email = (string?)e.Value ?? string.Empty })" />
        </div>
        <div>
            <label class="form-label">Phone <span style="color:red;">*</span></label>
            <input type="tel" class="form-control" value="@Reference.Phone"
                   @onchange="e => Update(Reference with { Phone = (string?)e.Value ?? string.Empty })" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Reference Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<Reference> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private async Task Update(Reference updated) => await OnChanged.InvokeAsync(updated);
}

@* Step indicator bar — shows progress through form steps *@

<div style="display:flex; justify-content:center; gap:0; margin-bottom:2rem;">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var step = i;
        var isCompleted = step < CurrentStep;
        var isCurrent = step == CurrentStep;
        var isFuture = step > CurrentStep;

        <div style="display:flex; align-items:center;">
            @if (step > 0)
            {
                <div style="width:3rem; height:2px; background:@(isCompleted || isCurrent ? "#0d6efd" : "#dee2e6");"></div>
            }

            <div style="display:flex; flex-direction:column; align-items:center; cursor:@(isCompleted ? "pointer" : "default");"
                 @onclick="() => { if (isCompleted) OnStepClicked.InvokeAsync(step); }">
                <div style="width:2.5rem; height:2.5rem; border-radius:50%; display:flex; align-items:center; justify-content:center;
                            font-weight:600; font-size:0.85rem;
                            background:@(isCurrent ? "#0d6efd" : isCompleted ? "#198754" : "#dee2e6");
                            color:@(isFuture ? "#6c757d" : "white");">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </div>
                <span style="margin-top:0.35rem; font-size:0.75rem; white-space:nowrap;
                             font-weight:@(isCurrent ? "600" : "400");
                             color:@(isFuture ? "#adb5bd" : "#212529");">
                    @StepNames[step]
                </span>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };
}

@* Step 1: Personal information form *@

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<h4 style="margin-bottom:1.5rem;">Personal Information</h4>

<div style="display:grid; grid-template-columns:1fr 1fr; gap:1rem; max-width:40rem;">
    <div style="grid-column:span 2;">
        <label class="form-label">Full Name <span style="color:red;">*</span></label>
        <input class="form-control" value="@FullName" @onchange="e => FullName = (string?)e.Value ?? string.Empty" />
    </div>
    <div>
        <label class="form-label">Email <span style="color:red;">*</span></label>
        <input type="email" class="form-control" value="@Email" @onchange="e => Email = (string?)e.Value ?? string.Empty" />
    </div>
    <div>
        <label class="form-label">Phone <span style="color:red;">*</span></label>
        <input type="tel" class="form-control" value="@Phone" @onchange="e => Phone = (string?)e.Value ?? string.Empty" />
    </div>
    <div style="grid-column:span 2;">
        <label class="form-label">Address <span style="color:red;">*</span></label>
        <input class="form-control" value="@Address" @onchange="e => Address = (string?)e.Value ?? string.Empty" />
    </div>
</div>

<div style="margin-top:1.5rem; display:flex; justify-content:flex-end;">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public PersonalInfo? Info { get; set; }
    [Parameter] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter] public EventCallback<string> OnValidateEmail { get; set; }

    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private string FullName = string.Empty;
    private string Email = string.Empty;
    private string Phone = string.Empty;
    private string Address = string.Empty;
    private string? ErrorMessage;
    private bool IsValidating;

    protected override void OnParametersSet()
    {
        if (Info is not null)
        {
            FullName = Info.FullName;
            Email = Info.Email;
            Phone = Info.Phone;
            Address = Info.Address;
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email.Trim());
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }
        finally
        {
            IsValidating = false;
        }

        await OnNext.InvokeAsync(new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim()));
    }
}

@* Step 2: Work history with dynamic list of entries *@

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<h4 style="margin-bottom:1.5rem;">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="@Entries[index]"
                   Index="index"
                   ShowRemove="@(Entries.Count > 1)"
                   OnChanged="e => UpdateEntry(index, e)"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary" @onclick="AddEntry">
    + Add Another Position
</button>

<div style="margin-top:1.5rem; display:flex; justify-content:space-between;">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntry>? InitialEntries { get; set; }
    [Parameter] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<WorkEntry> Entries = new();
    private string? ErrorMessage;

    protected override void OnParametersSet()
    {
        if (Entries.Count == 0)
        {
            Entries = InitialEntries?.Count > 0
                ? InitialEntries.ToList()
                : new List<WorkEntry> { new("", "", DateTime.Today, null, "") };
        }
    }

    private void UpdateEntry(int index, WorkEntry updated) => Entries[index] = updated;

    private void RemoveEntry(int index) => Entries.RemoveAt(index);

    private void AddEntry() => Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries.ToList());
    }
}

@* Step 3: References (2-3 entries) *@

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<h4 style="margin-bottom:1.5rem;">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="@References[index]"
                   Index="index"
                   ShowRemove="@(References.Count > 2)"
                   OnChanged="e => UpdateReference(index, e)"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary" @onclick="AddReference">
        + Add Reference
    </button>
}

<div style="margin-top:1.5rem; display:flex; justify-content:space-between;">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<Reference>? InitialReferences { get; set; }
    [Parameter] public EventCallback<List<Reference>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<Reference> References = new();
    private string? ErrorMessage;

    protected override void OnParametersSet()
    {
        if (References.Count == 0)
        {
            References = InitialReferences?.Count > 0
                ? InitialReferences.ToList()
                : new List<Reference>
                {
                    new("", "", "", ""),
                    new("", "", "", "")
                };
        }
    }

    private void UpdateReference(int index, Reference updated) => References[index] = updated;

    private void RemoveReference(int index) => References.RemoveAt(index);

    private void AddReference() => References.Add(new Reference("", "", "", ""));

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }

        await OnNext.InvokeAsync(References.ToList());
    }
}

@* Step 4: Cover letter textarea with character count *@

<h4 style="margin-bottom:1.5rem;">Cover Letter</h4>

<div style="max-width:50rem;">
    <textarea class="form-control" rows="12" value="@CoverLetterText"
              maxlength="@MaxLength"
              @oninput="e => CoverLetterText = (string?)e.Value ?? string.Empty"
              placeholder="Write your cover letter here..."></textarea>
    <div style="text-align:right; margin-top:0.25rem; font-size:0.85rem; color:#6c757d;">
        @CoverLetterText.Length / @MaxLength characters
    </div>
</div>

<div style="margin-top:1.5rem; display:flex; justify-content:space-between;">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string? InitialText { get; set; }
    [Parameter] public EventCallback<string> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string CoverLetterText = string.Empty;

    protected override void OnParametersSet()
    {
        if (InitialText is not null && CoverLetterText == string.Empty)
        {
            CoverLetterText = InitialText;
        }
    }

    private async Task HandleNext() => await OnNext.InvokeAsync(CoverLetterText);
}

@* Step 5: Read-only review of all data with submit *@

@if (Submitted)
{
    <div class="alert alert-success" style="text-align:center; padding:2rem;">
        <h4>Application Submitted Successfully!</h4>
        <p style="font-size:1.1rem; margin-top:1rem;">Your application ID is <strong>#@ApplicationId</strong></p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <h4 style="margin-bottom:1.5rem;">Review & Submit</h4>

    @* Personal Info *@
    <div style="border:1px solid #dee2e6; border-radius:8px; padding:1rem; margin-bottom:1rem;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.5rem;">
            <h5 style="margin:0;">Personal Information</h5>
            <button class="btn btn-link btn-sm" @onclick='() => OnEdit.InvokeAsync(0)'>Edit</button>
        </div>
        <div style="display:grid; grid-template-columns:1fr 1fr; gap:0.25rem 1rem;">
