            <h5 style="margin:0;">Work History</h5>
            <button class="btn btn-link btn-sm" @onclick='() => OnEdit.InvokeAsync(1)'>Edit</button>
        </div>
        @if (WorkEntries is not null)
        {
            @foreach (var entry in WorkEntries)
