                <div style="padding:0.5rem 0; border-bottom:1px solid #f0f0f0;">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span style="color:#6c757d; font-size:0.85rem;">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p style="margin:0.25rem 0 0; font-size:0.9rem;">@entry.Description</p>
                    }
                </div>
            }
        }
    </div>

    @* References *@
    <div style="border:1px solid #dee2e6; border-radius:8px; padding:1rem; margin-bottom:1rem;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.5rem;">
            <h5 style="margin:0;">References</h5>
            <button class="btn btn-link btn-sm" @onclick='() => OnEdit.InvokeAsync(2)'>Edit</button>
        </div>
        @if (References is not null)
        {
            @foreach (var r in References)
            {
                <div style="padding:0.25rem 0;">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        }
    </div>

    @* Cover Letter *@
    <div style="border:1px solid #dee2e6; border-radius:8px; padding:1rem; margin-bottom:1.5rem;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.5rem;">
            <h5 style="margin:0;">Cover Letter</h5>
            <button class="btn btn-link btn-sm" @onclick='() => OnEdit.InvokeAsync(3)'>Edit</button>
        </div>
        <p style="white-space:pre-wrap; margin:0;">@CoverLetter</p>
    </div>

    <div style="display:flex; justify-content:space-between;">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter] public PersonalInfo? Personal { get; set; }
    [Parameter] public List<WorkEntry>? WorkEntries { get; set; }
    [Parameter] public List<Reference>? References { get; set; }
    [Parameter] public string? CoverLetter { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmitted { get; set; }

    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private bool IsSubmitting;
    private bool Submitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;

        try
        {
            var application = new JobApplication(
                Personal!,
                new WorkHistory(WorkEntries!),
                References!,
                CoverLetter ?? string.Empty
            );

            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            Submitted = true;
            await OnSubmitted.InvokeAsync();
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

@page "/apply"
@rendermode InteractiveServer

@using sv_36f4efedc28845b281d0f0740479c67c.Models

<PageTitle>Job Application</PageTitle>

<div style="max-width:52rem; margin:2rem auto; padding:0 1rem;">
    <h2 style="text-align:center; margin-bottom:1.5rem;">Job Application</h2>

    <StepIndicator CurrentStep="@currentStep" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Info="@personalInfo" OnNext="HandlePersonalNext" />
            break;
        case 1:
            <WorkHistoryStep InitialEntries="@workEntries" OnNext="HandleWorkNext" OnBack="GoBack" />
            break;
        case 2:
            <ReferencesStep InitialReferences="@references" OnNext="HandleReferencesNext" OnBack="GoBack" />
            break;
        case 3:
            <CoverLetterStep InitialText="@coverLetter" OnNext="HandleCoverLetterNext" OnBack="GoBack" />
            break;
        case 4:
            <ReviewStep Personal="@personalInfo"
                        WorkEntries="@workEntries"
                        References="@references"
                        CoverLetter="@coverLetter"
                        OnEdit="GoToStep"
                        OnBack="GoBack"
                        OnSubmitted="HandleSubmitted" />
            break;
    }
</div>

@code {
    private int currentStep;
    private PersonalInfo? personalInfo;
    private List<WorkEntry>? workEntries;
    private List<Reference>? references;
    private string coverLetter = string.Empty;

    private void GoToStep(int step)
    {
        if (step < currentStep)
            currentStep = step;
    }

    private void GoBack() => currentStep = Math.Max(0, currentStep - 1);

    private void HandlePersonalNext(PersonalInfo info)
    {
        personalInfo = info;
        currentStep = 1;
    }

    private void HandleWorkNext(List<WorkEntry> entries)
    {
        workEntries = entries;
        currentStep = 2;
    }

    private void HandleReferencesNext(List<Reference> refs)
    {
        references = refs;
        currentStep = 3;
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        currentStep = 4;
    }

    private void HandleSubmitted()
    {
        // Could navigate away or reset state if needed
    }
}

namespace sv_36f4efedc28845b281d0f0740479c67c.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@* Leaf component: renders a single work entry with editable fields *@

<div style="border:1px solid #dee2e6; border-radius:8px; padding:1rem; margin-bottom:1rem; background:#f8f9fa;">
    <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.75rem;">
        <strong>Position @(Index + 1)</strong>
        @if (ShowRemove)
        {
            <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
        }
    </div>

    <div style="display:grid; grid-template-columns:1fr 1fr; gap:0.75rem;">
        <div>
            <label class="form-label">Company Name <span style="color:red;">*</span></label>
            <input class="form-control" value="@Entry.Company"
                   @onchange="e => Update(Entry with { Company = (string?)e.Value ?? string.Empty })" />
        </div>
        <div>
            <label class="form-label">Job Title <span style="color:red;">*</span></label>
            <input class="form-control" value="@Entry.Title"
                   @onchange="e => Update(Entry with { Title = (string?)e.Value ?? string.Empty })" />
        </div>
        <div>
            <label class="form-label">Start Date <span style="color:red;">*</span></label>
            <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                   @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? string.Empty) })" />
        </div>
        <div>
            <label class="form-label">End Date</label>
            <input type="date" class="form-control" value="@(Entry.EndDate?.ToString("yyyy-MM-dd"))"
                   disabled="@IsCurrent"
                   @onchange="e => Update(Entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })" />
            <div class="form-check mt-1">
                <input type="checkbox" class="form-check-input" id="@($"current-{Index}")"
                       checked="@IsCurrent" @onchange="ToggleCurrent" />
                <label class="form-check-label" for="@($"current-{Index}")">Currently working here</label>
            </div>
        </div>
    </div>

    <div style="margin-top:0.75rem;">
        <label class="form-label">Description</label>
        <textarea class="form-control" rows="3" value="@Entry.Description"
                  @onchange="e => Update(Entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null;

    private async Task Update(WorkEntry updated) => await OnChanged.InvokeAsync(updated);

    private async Task ToggleCurrent(ChangeEventArgs e)
    {
        var current = (bool?)e.Value ?? false;
        var updated = current
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        await OnChanged.InvokeAsync(updated);
    }
}

