@* Step indicator bar — shows progress through form steps *@

<div style="display:flex; justify-content:center; gap:0; margin-bottom:2rem;">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var step = i;
        var isCompleted = step < CurrentStep;
        var isCurrent = step == CurrentStep;
        var isFuture = step > CurrentStep;

        <div style="display:flex; align-items:center;">
            @if (step > 0)
            {
                <div style="width:3rem; height:2px; background:@(isCompleted || isCurrent ? "#0d6efd" : "#dee2e6");"></div>
            }

            <div style="display:flex; flex-direction:column; align-items:center; cursor:@(isCompleted ? "pointer" : "default");"
                 @onclick="() => { if (isCompleted) OnStepClicked.InvokeAsync(step); }">
                <div style="width:2.5rem; height:2.5rem; border-radius:50%; display:flex; align-items:center; justify-content:center;
                            font-weight:600; font-size:0.85rem;
                            background:@(isCurrent ? "#0d6efd" : isCompleted ? "#198754" : "#dee2e6");
                            color:@(isFuture ? "#6c757d" : "white");">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </div>
                <span style="margin-top:0.35rem; font-size:0.75rem; white-space:nowrap;
                             font-weight:@(isCurrent ? "600" : "400");
                             color:@(isFuture ? "#adb5bd" : "#212529");">
                    @StepNames[step]
                </span>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };
}

@* Step 1: Personal information form *@

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<h4 style="margin-bottom:1.5rem;">Personal Information</h4>

<div style="display:grid; grid-template-columns:1fr 1fr; gap:1rem; max-width:40rem;">
    <div style="grid-column:span 2;">
        <label class="form-label">Full Name <span style="color:red;">*</span></label>
        <input class="form-control" value="@FullName" @onchange="e => FullName = (string?)e.Value ?? string.Empty" />
    </div>
    <div>
        <label class="form-label">Email <span style="color:red;">*</span></label>
        <input type="email" class="form-control" value="@Email" @onchange="e => Email = (string?)e.Value ?? string.Empty" />
    </div>
    <div>
        <label class="form-label">Phone <span style="color:red;">*</span></label>
        <input type="tel" class="form-control" value="@Phone" @onchange="e => Phone = (string?)e.Value ?? string.Empty" />
    </div>
    <div style="grid-column:span 2;">
        <label class="form-label">Address <span style="color:red;">*</span></label>
        <input class="form-control" value="@Address" @onchange="e => Address = (string?)e.Value ?? string.Empty" />
    </div>
</div>

<div style="margin-top:1.5rem; display:flex; justify-content:flex-end;">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public PersonalInfo? Info { get; set; }
    [Parameter] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter] public EventCallback<string> OnValidateEmail { get; set; }

    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private string FullName = string.Empty;
    private string Email = string.Empty;
    private string Phone = string.Empty;
    private string Address = string.Empty;
    private string? ErrorMessage;
    private bool IsValidating;

    protected override void OnParametersSet()
    {
        if (Info is not null)
        {
            FullName = Info.FullName;
            Email = Info.Email;
            Phone = Info.Phone;
            Address = Info.Address;
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email.Trim());
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }
        finally
        {
            IsValidating = false;
        }

        await OnNext.InvokeAsync(new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim()));
    }
}

