</div>

@code {
    [Parameter] public List<WorkEntry>? InitialEntries { get; set; }
    [Parameter] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<WorkEntry> Entries = new();
    private string? ErrorMessage;

    protected override void OnParametersSet()
    {
        if (Entries.Count == 0)
        {
            Entries = InitialEntries?.Count > 0
                ? InitialEntries.ToList()
                : new List<WorkEntry> { new("", "", DateTime.Today, null, "") };
        }
    }

    private void UpdateEntry(int index, WorkEntry updated) => Entries[index] = updated;

    private void RemoveEntry(int index) => Entries.RemoveAt(index);

    private void AddEntry() => Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries.ToList());
    }
}

