                </div>
            }
        }
    </div>

    @* References *@
    <div style="border:1px solid #dee2e6; border-radius:8px; padding:1rem; margin-bottom:1rem;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.5rem;">
            <h5 style="margin:0;">References</h5>
            <button class="btn btn-link btn-sm" @onclick='() => OnEdit.InvokeAsync(2)'>Edit</button>
        </div>
        @if (References is not null)
        {
            @foreach (var r in References)
            {
                <div style="padding:0.25rem 0;">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        }
    </div>

    @* Cover Letter *@
    <div style="border:1px solid #dee2e6; border-radius:8px; padding:1rem; margin-bottom:1.5rem;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.5rem;">
            <h5 style="margin:0;">Cover Letter</h5>
            <button class="btn btn-link btn-sm" @onclick='() => OnEdit.InvokeAsync(3)'>Edit</button>
        </div>
        <p style="white-space:pre-wrap; margin:0;">@CoverLetter</p>
    </div>

    <div style="display:flex; justify-content:space-between;">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter] public PersonalInfo? Personal { get; set; }
    [Parameter] public List<WorkEntry>? WorkEntries { get; set; }
    [Parameter] public List<Reference>? References { get; set; }
    [Parameter] public string? CoverLetter { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmitted { get; set; }

    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private bool IsSubmitting;
    private bool Submitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;

        try
        {
            var application = new JobApplication(
                Personal!,
                new WorkHistory(WorkEntries!),
                References!,
                CoverLetter ?? string.Empty
            );

            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            Submitted = true;
            await OnSubmitted.InvokeAsync();
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}
