toolArgs.file_text:
@* Step 3: References (2-3 entries) *@

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<h4 style="margin-bottom:1.5rem;">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="@References[index]"
                   Index="index"
                   ShowRemove="@(References.Count > 2)"
                   OnChanged="e => UpdateReference(index, e)"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary" @onclick="AddReference">
        + Add Reference
    </button>
}

<div style="margin-top:1.5rem; display:flex; justify-content:space-between;">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<Reference>? InitialReferences { get; set; }
    [Parameter] public EventCallback<List<Reference>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<Reference> References = new();
    private string? ErrorMessage;

    protected override void OnParametersSet()
    {
        if (References.Count == 0)
        {
            References = InitialReferences?.Count > 0
                ? InitialReferences.ToList()
                : new List<Reference>
                {
                    new("", "", "", ""),
                    new("", "", "", "")
                };
        }
    }

    private void UpdateReference(int index, Reference updated) => References[index] = updated;

    private void RemoveReference(int index) => References.RemoveAt(index);

    private void AddReference() => References.Add(new Reference("", "", "", ""));

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }

        await OnNext.InvokeAsync(References.ToList());
    }
}

