toolArgs.file_text:
@page "/apply"
@rendermode InteractiveServer

@using sv_36f4efedc28845b281d0f0740479c67c.Models

<PageTitle>Job Application</PageTitle>

<div style="max-width:52rem; margin:2rem auto; padding:0 1rem;">
    <h2 style="text-align:center; margin-bottom:1.5rem;">Job Application</h2>

    <StepIndicator CurrentStep="@currentStep" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Info="@personalInfo" OnNext="HandlePersonalNext" />
            break;
        case 1:
            <WorkHistoryStep InitialEntries="@workEntries" OnNext="HandleWorkNext" OnBack="GoBack" />
            break;
        case 2:
            <ReferencesStep InitialReferences="@references" OnNext="HandleReferencesNext" OnBack="GoBack" />
            break;
        case 3:
            <CoverLetterStep InitialText="@coverLetter" OnNext="HandleCoverLetterNext" OnBack="GoBack" />
            break;
        case 4:
            <ReviewStep Personal="@personalInfo"
                        WorkEntries="@workEntries"
                        References="@references"
                        CoverLetter="@coverLetter"
                        OnEdit="GoToStep"
                        OnBack="GoBack"
                        OnSubmitted="HandleSubmitted" />
            break;
    }
</div>

@code {
    private int currentStep;
    private PersonalInfo? personalInfo;
    private List<WorkEntry>? workEntries;
    private List<Reference>? references;
    private string coverLetter = string.Empty;

    private void GoToStep(int step)
    {
        if (step < currentStep)
            currentStep = step;
    }

    private void GoBack() => currentStep = Math.Max(0, currentStep - 1);

    private void HandlePersonalNext(PersonalInfo info)
    {
        personalInfo = info;
        currentStep = 1;
    }

    private void HandleWorkNext(List<WorkEntry> entries)
    {
        workEntries = entries;
        currentStep = 2;
    }

    private void HandleReferencesNext(List<Reference> refs)
    {
        references = refs;
        currentStep = 3;
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        currentStep = 4;
    }

    private void HandleSubmitted()
    {
        // Could navigate away or reset state if needed
    }
}

